{"type":"message","id":"db89da2e","parentId":"50d92752","timestamp":"2026-03-19T18:42:22.491Z","message":{"role":"toolResult","toolCallId":"call_6Yug0pnVXRejesoMFbqcxG4g|fc_02d9871a09466ea10169bc438e93bc8191bbd0022247b387b8","toolName":"read","content":[{"type":"text","text":"import assert from "node:assert/strict";
import { spawn } from "node:child_process";
import { once } from "node:events";
import test from "node:test";

import { terminateActorProcess } from "../../src/actors/termination";

test("terminateActorProcess force-kills a SIGTERM-ignoring child", async () => {
	const child = spawn(
		process.execPath,
		[
			"-e",
			`
process.on("SIGTERM", () => {
  // Intentionally ignore SIGTERM.
});
setInterval(() => {}, 1000);
`,
		],
		{ stdio: "ignore" },
	);

	const exitPromise = once(child, "exit") as Promise<[number | null, NodeJS.Signals | null]>;

	try {
		const result = await terminateActorProcess(child, { sigtermGraceMs: 50 });
		const [exitCode, signal] = await exitPromise;

		assert.equal(exitCode, null);
		assert.equal(signal, "SIGKILL");
		assert.equal(result.forced, true);
		assert.equal(result.signal, "SIGKILL");
	} finally {
		if (child.exitCode === null && child.signalCode === null) {
			child.kill("SIGKILL");
			await exitPromise;
		}
	}
});
"}],"isError":false,"timestamp":1773945742491}}
