const fs = require('fs');
const path = require('path');
const dir = '.pi/threads';
const files = fs.readdirSync(dir).filter(f => f.startsWith('refactor-') && f.endsWith('.jsonl')).sort();
for (const file of files) {
  const lines = fs.readFileSync(path.join(dir,file),'utf8').trim().split('\n');
  const edits = [];
  for (const line of lines) {
    if (!line.trim()) continue;
    let obj;
    try { obj = JSON.parse(line); } catch { continue; }
    if (obj.type !== 'message' || !obj.message || obj.message.role !== 'assistant') continue;
    const parts = obj.message.content || [];
    for (const part of parts) {
      if (part.type === 'toolCall' && (part.name === 'write' || part.name === 'edit')) {
        const args = part.arguments || {};
        const p = args.path || args.file_path || null;
        edits.push({tool: part.name, path: p});
      }
    }
  }
  console.log(`\n${file}`);
  if (edits.length === 0) {
    console.log('  (no write/edit calls logged)');
    continue;
  }
  for (const e of edits) {
    console.log(`  ${e.tool} ${e.path}`);
  }
}
