export async function terminateActorProcess(
	child: ChildProcess,
	{ sigtermGraceMs }: TerminateActorProcessOptions,
): Promise<TerminateActorProcessResult> {
	const exitedBeforeTermination = getExitSnapshot(child);
	if (exitedBeforeTermination) {
		return {
			forced: false,
			signal: null,
