const fs=require('fs');
const path=require('path');
const dir='.pi/threads';
const files=fs.readdirSync(dir).filter(f=>f.startsWith('refactor-')&&f.endsWith('.jsonl')).sort();
const byPath=new Map();
for(const file of files){
  const thread=file.replace('.jsonl','');
  const lines=fs.readFileSync(path.join(dir,file),'utf8').trim().split('\n');
  for(const line of lines){
    if(!line.trim()) continue;
    let obj; try{obj=JSON.parse(line);}catch{continue;}
    if(obj.type!=='message'||obj.message?.role!=='assistant') continue;
    for(const part of obj.message.content||[]){
      if(part.type!=='toolCall') continue;
      if(part.name!=='write' && part.name!=='edit') continue;
      const args=part.arguments||{};
      let p=args.path||args.file_path;
      if(!p) continue;
      p=p.replace('/home/bitzaven/CodingProjects/pi-threads/','');
      if(!byPath.has(p)) byPath.set(p,[]);
      byPath.get(p).push({thread,tool:part.name,ts:obj.timestamp});
    }
  }
}
for(const [p,events] of [...byPath.entries()].sort((a,b)=>a[0].localeCompare(b[0]))){
  const threads=[...new Set(events.map(e=>e.thread))];
  if(threads.length>1){
    const last=events.sort((a,b)=>a.ts.localeCompare(b.ts)).at(-1);
    console.log(`${p}\n  threads: ${threads.join(', ')}\n  last: ${last.thread} ${last.tool} ${last.ts}`);
  }
}
