function formatUsage(usage: UsageStats, model?: string): string {
	const parts: string[] = [];
	if (usage.turns) parts.push(`${usage.turns} turn${usage.turns > 1 ? "s" : ""}`);
	if (usage.input) parts.push(`↑${formatTokens(usage.input)}`);
	if (usage.output) parts.push(`↓${formatTokens(usage.output)}`);
	if (usage.cacheRead) parts.push(`R${formatTokens(usage.cacheRead)}`);
	if (usage.cacheWrite) parts.push(`W${formatTokens(usage.cacheWrite)}`);
	if (usage.cost) parts.push(`$${usage.cost.toFixed(4)}`);
	if (usage.contextTokens > 0) parts.push(`ctx:${formatTokens(usage.contextTokens)}`);
	if (model) parts.push(model);
	return parts.join(" ");
}

// ─── Thread Execution ───

async function runThreadAction(
	cwd: string,
	threadName: string,
	action: string,
	model: string | undefined,
	signal: AbortSignal | undefined,
	onUpdate: ((partial: AgentToolResult<DispatchDetails>) => void) | undefined,
	episodeNumber: number,
): Promise<ThreadActionResult> {
	ensureThreadsDir(cwd);
	const sessionPath = getThreadSessionPath(cwd, threadName);
	const isNewThread = !fs.existsSync(sessionPath);

	const result: ThreadActionResult = {
		thread: threadName,
		action,
		exitCode: 0,
		messages: [],
		stderr: "",
		usage: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, cost: 0, contextTokens: 0, turns: 0 },
		model,
		sessionPath,
		isNewThread,
	};

	const trackUsage = (msg: Message) => {
		if (msg.role === "assistant") {
			result.usage.turns++;
			const usage = msg.usage;
			if (usage) {
				result.usage.input += usage.input || 0;
				result.usage.output += usage.output || 0;
				result.usage.cacheRead += usage.cacheRead || 0;
				result.usage.cacheWrite += usage.cacheWrite || 0;
				result.usage.cost += usage.cost?.total || 0;
				result.usage.contextTokens = usage.totalTokens || 0;
			}
			if (!result.model && msg.model) result.model = msg.model;
			if (msg.stopReason) result.stopReason = msg.stopReason;
			if (msg.errorMessage) result.errorMessage = msg.errorMessage;
		}
	};

	const emitUpdate = () => {
		if (onUpdate) {
			const lastText = getFinalOutput(result.messages);
			onUpdate({
				content: [{ type: "text", text: lastText || "(running...)" }],
				details: {
					mode: "single",
					items: [{
						thread: threadName,
						action,
						episode: "(running...)",
						episodeNumber,
						result,
					}],
				},
			});
		}
	};

	const runId = `${threadName}:${episodeNumber}:${Date.now()}:${Math.random().toString(36).slice(2, 8)}`;

	const backendResult = await runBackend.run(
		{
			runId,
			cwd,
			action,
			sessionKey: threadName,
			model,
			systemPrompt: THREAD_WORKER_PROMPT,
		},
		{
			signal,
			observer: {
				onMessage: (message) => {
					const threadedMessage = message as Message;
					result.messages.push(threadedMessage);
					trackUsage(threadedMessage);
					emitUpdate();
				},
				onStderr: (chunk) => {
					result.stderr += chunk;
				},
			},
		},
	);

	result.messages = backendResult.messages as Message[];
	result.stderr = backendResult.stderr;
	result.usage = {
		input: backendResult.usage.input,
		output: backendResult.usage.output,
		cacheRead: backendResult.usage.cacheRead,
		cacheWrite: backendResult.usage.cacheWrite,
		cost: backendResult.usage.cost,
		contextTokens: backendResult.usage.contextTokens,
		turns: backendResult.usage.turns,
	};
	result.model = backendResult.model ?? result.model;
	result.stopReason = backendResult.stopReason;
	result.errorMessage = backendResult.errorMessage;
	result.exitCode = backendResult.finalState.exitCode ?? (backendResult.finalState.signal ? 1 : 0);

	if (!result.stopReason && backendResult.finalState.requestedTerminationReason === "abort") {
		result.stopReason = "aborted";
	}

	return result;
}

// ─── Episode Generation ───

function getFinalOutput(messages: Message[]): string {
	for (let i = messages.length - 1; i >= 0; i--) {
		const msg = messages[i];
		if (msg.role === "assistant") {
			for (const part of msg.content) {
				if (part.type === "text") return part.text;
			}
		}
	}
	return "";
}

// ─── Rendering Helpers ───

function formatToolCall(
	toolName: string,
	args: Record<string, unknown>,
	fg: (color: any, text: string) => string,
): string {
	const shorten = (p: string) => {
		const home = os.homedir();
		return p.startsWith(home) ? `~${p.slice(home.length)}` : p;
	};
	switch (toolName) {
		case "bash": {
			const cmd = ((args.command as string) || "...").replace(/\n/g, " ").replace(/\s+/g, " ").trim();
			const preview = cmd.length > 80 ? cmd.slice(0, 80) + "..." : cmd;
			return fg("muted", "$ ") + fg("toolOutput", preview);
		}
		case "read": {
			const filePath = shorten(((args.file_path || args.path || "...") as string));
			return fg("muted", "read ") + fg("accent", filePath);
		}
		case "write": {
			const filePath = shorten(((args.file_path || args.path || "...") as string));
			return fg("muted", "write ") + fg("accent", filePath);
		}
		case "edit": {
			const filePath = shorten(((args.file_path || args.path || "...") as string));
			return fg("muted", "edit ") + fg("accent", filePath);
		}
		default: {
			const s = JSON.stringify(args);
			return fg("accent", toolName) + fg("dim", ` ${s.length > 60 ? s.slice(0, 60) + "..." : s}`);
		}
	}
}

type DisplayItem = { type: "text"; text: string } | { type: "toolCall"; name: string; args: Record<string, any> };

function getDisplayItems(messages: Message[]): DisplayItem[] {
	const items: DisplayItem[] = [];
	for (const msg of messages) {
		if (msg.role === "assistant") {
			for (const part of msg.content) {
				if (part.type === "text") items.push({ type: "text", text: part.text });
				else if (part.type === "toolCall") items.push({ type: "toolCall", name: part.name, args: part.arguments });
			}
		}
	}
	return items;
}

